export const meta = {
  name: 'qa-oauth2-oidc',
  description: 'QA workflow: OAuth2/OpenID Connect in Nablarch web app',
  phases: [
    { title: 'Semantic Search' },
    { title: 'Read Sections' },
    { title: 'Generate Answer' }
  ]
}

phase('Semantic Search')
const searchResult = await agent(
  `Execute semantic search for the following query against Nablarch knowledge files.

Query: "NablarchでOAuth2やOpenID Connectによる認証を実装したい。Nablarchにその仕組みは組み込まれているか？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

Knowledge base location: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

Steps:
1. List all JSON files in the knowledge directory and subdirectories using Glob pattern: **/*.json
2. For each file, read it to understand its content (title, sections summary)
3. Based on the query about OAuth2, OpenID Connect, authentication/security in Nablarch web applications, select the most relevant pages
4. For each selected page, identify relevant sections

Focus on:
- Authentication (認証) mechanisms
- Security (セキュリティ) features
- OAuth2, OpenID Connect
- Session management
- Login/logout functionality
- Web application security

Return a JSON object with:
{
  "selected_pages": [{"path": "<relative to knowledge/>", "reason": "<why selected>"}],
  "excluded_pages": [{"path": "<relative to knowledge/>", "reason": "<why skipped>"}],
  "selected_sections": [{"file": "<full path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}],
  "excluded_sections": [{"file": "<full path>", "section_id": "<sN>", "reason": "<why skipped>"}]
}`,
  {
    label: 'semantic-search',
    phase: 'Semantic Search',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('Read Sections')
// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

log(`Reading ${sectionsToRead.length} sections (${highSections.length} high, ${Math.min(partialSections.length, 10 - highSections.length)} partial)`)

const sectionArgs = sectionsToRead.map(s => {
  const fileName = s.file.split('/').pop()
  return `"${s.file}:${s.section_id}"`
})

let sectionsContent = ''
if (sectionsToRead.length > 0) {
  sectionsContent = await agent(
    `Run this bash command and return the complete output verbatim:
bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${sectionArgs.join(' ')}

Return the raw output exactly as-is.`,
    { label: 'read-sections', phase: 'Read Sections' }
  )
}

phase('Generate Answer')
const answerResult = await agent(
  `You are answering a question about Nablarch framework in Japanese.

Question: "NablarchでOAuth2やOpenID Connectによる認証を実装したい。Nablarchにその仕組みは組み込まれているか？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

Sections content from knowledge files:
${sectionsContent || '(empty - no sections found)'}

Selected sections metadata:
${JSON.stringify(sectionsToRead, null, 2)}

Instructions:
1. If sections_content is empty, output: "この情報は知識ファイルに含まれていません。"
2. Otherwise, generate a Japanese answer in this format:

**結論**: Direct answer (1-2 sentences) - include specific method/class names if applicable

**根拠**: Code/config examples or spec info backing the conclusion (use code blocks)

**注意点**: Constraints, common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

IMPORTANT:
- Stay within 500 tokens (up to 800 for complex questions)
- Focus on ウェブアプリケーション processing type
- Only state what is explicitly in the sections - do not infer
- For gaps, write "この情報は知識ファイルの対象範囲外です"

Then verify: check each Nablarch-specific claim (API names, class names, config methods, behavior specs, constraints) against the section content. 
- verify_result = PASS if all claims are supported
- verify_result = FAIL + list issues if any claim is unsupported

Return JSON:
{
  "answer_text": "<the Japanese answer>",
  "verify_result": "PASS" or "FAIL",
  "issues": ["<unsupported claim 1>", ...],
  "answer_sections_used": [{"ref": "<file.json:sN>", "reason": "<why used>"}],
  "answer_sections_unused": [{"ref": "<file.json:sN>", "reason": "<why not used>"}]
}`,
  {
    label: 'generate-answer',
    phase: 'Generate Answer',
    schema: {
      type: 'object',
      properties: {
        answer_text: { type: 'string' },
        verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
        issues: { type: 'array', items: { type: 'string' } },
        answer_sections_used: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        },
        answer_sections_unused: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        }
      },
      required: ['answer_text', 'verify_result', 'issues', 'answer_sections_used', 'answer_sections_unused']
    }
  }
)

// Handle verify result
let finalAnswer = answerResult.answer_text
if (answerResult.verify_result === 'FAIL' && answerResult.issues && answerResult.issues.length > 0) {
  log(`Verify FAIL - regenerating without unsupported claims: ${answerResult.issues.join(', ')}`)
  const regenResult = await agent(
    `You are answering a question about Nablarch framework in Japanese. A previous answer had unsupported claims that must be removed.

Question: "NablarchでOAuth2やOpenID Connectによる認証を実装したい。Nablarchにその仕組みは組み込まれているか？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

Sections content from knowledge files:
${sectionsContent || '(empty)'}

UNSUPPORTED CLAIMS TO EXCLUDE (do not include these in the new answer):
${answerResult.issues.join('\n')}

Generate a revised Japanese answer in this format:
**結論**: Direct answer (1-2 sentences)
**根拠**: Supporting evidence from sections
**注意点**: Constraints (omit if nothing applies)
参照: Cited sections

Only include claims directly stated in the section content.`,
    { label: 'regen-answer', phase: 'Generate Answer' }
  )
  finalAnswer = regenResult
}

return {
  search: searchResult,
  sectionsToRead: sectionsToRead,
  sectionsContent: sectionsContent,
  answerResult: answerResult,
  finalAnswer: finalAnswer
}

